#include "biblia.h"

void Biblia::CarregarJeremias(Biblia* b) {
    b->dados[JEREMIAS].nome = wxT("Jeremias");

    b->dados[JEREMIAS].capitulos[1].versos[1] = wxT("Ora veio a palavra do Senhor a Jonas, filho de Amitai, dizendo:");
    b->dados[JEREMIAS].capitulos[1].versos[2] = wxT("Levanta-te, vai à grande cidade de Nínive, e clama contra ela, porque a sua malícia subiu até mim.");
    b->dados[JEREMIAS].capitulos[1].versos[3] = wxT("Jonas, porém, levantou-se para fugir da presença do Senhor para Társis. E, descendo a Jope, achou um navio que ia para Társis; pagou, pois, a sua passagem, e desceu para dentro dele, para ir com eles para Társis, da presença do Senhor.");
    b->dados[JEREMIAS].capitulos[1].versos[4] = wxT("Mas o Senhor lançou sobre o mar um grande vento, e fez-se no mar uma grande tempestade, de modo que o navio estava a ponto de se despedaçar.");
    b->dados[JEREMIAS].capitulos[1].versos[5] = wxT("Então os marinheiros tiveram medo, e clamavam cada um ao seu deus, e alijaram ao mar a carga que estava no navio, para o aliviarem; Jonas, porém, descera ao porão do navio; e, tendo-se deitado, dormia um profundo sono.");
    b->dados[JEREMIAS].capitulos[1].versos[6] = wxT("O mestre do navio, pois, chegou-se a ele, e disse-lhe: Que estás fazendo, ó tu que dormes? Levanta-te, clama ao teu deus; talvez assim ele se lembre de nós, para que não pereçamos.");
    b->dados[JEREMIAS].capitulos[1].versos[7] = wxT("E dizia cada um ao seu companheiro: Vinde, e lancemos sortes, para sabermos por causa de quem nos sobreveio este mal. E lançaram sortes, e a sorte caiu sobre Jonas.");
    b->dados[JEREMIAS].capitulos[1].versos[8] = wxT("Então lhe disseram: Declara-nos tu agora, por causa de quem nos sobreveio este mal. Que ocupação é a tua? Donde vens? Qual é a tua terra? E de que povo és tu?");
    b->dados[JEREMIAS].capitulos[1].versos[9] = wxT("Respondeu-lhes ele: Eu sou hebreu, e temo ao Senhor, o Deus do céu, que fez o mar e a terra seca.");
    b->dados[JEREMIAS].capitulos[1].versos[10] = wxT("Então estes homens se encheram de grande temor, e lhe disseram: Que é isso que fizeste? pois sabiam os homens que fugia da presença do Senhor, porque ele lho tinha declarado.");
    b->dados[JEREMIAS].capitulos[1].versos[11] = wxT("Ainda lhe perguntaram: Que te faremos nós, para que o mar se nos acalme? Pois o mar se ia tornando cada vez mais tempestuoso.");
    b->dados[JEREMIAS].capitulos[1].versos[12] = wxT("Respondeu-lhes ele: Levantai-me, e lançai-me ao mar, e o mar se vos aquietará; porque eu sei que por minha causa vos sobreveio esta grande tempestade.");
    b->dados[JEREMIAS].capitulos[1].versos[13] = wxT("Entretanto os homens se esforçavam com os remos para tornar a alcançar a terra; mas não podiam, porquanto o mar se ia embravecendo cada vez mais contra eles.");
    b->dados[JEREMIAS].capitulos[1].versos[14] = wxT("Por isso clamaram ao Senhor, e disseram: Nós te rogamos, ó Senhor, que não pereçamos por causa da vida deste homem, e que não ponhas sobre nós o sangue inocente; porque tu, Senhor, fizeste como te aprouve.");
    b->dados[JEREMIAS].capitulos[1].versos[15] = wxT("Então levantaram a Jonas, e o lançaram ao mar; e cessou o mar da sua fúria.");
    b->dados[JEREMIAS].capitulos[1].versos[16] = wxT("Temeram, pois, os homens ao Senhor com grande temor; e ofereceram sacrifícios ao Senhor, e fizeram votos.");
    b->dados[JEREMIAS].capitulos[1].versos[17] = wxT("Então o Senhor deparou um grande peixe, para que tragasse a Jonas; e esteve Jonas três dias e três noites nas entranhas do peixe.");

    b->dados[JEREMIAS].capitulos[2].versos[1] = wxT("E orou Jonas ao Senhor, seu Deus, lá das entranhas do peixe;");
    b->dados[JEREMIAS].capitulos[2].versos[2] = wxT("e disse: Na minha angústia clamei ao senhor, e ele me respondeu; do ventre do Seol gritei, e tu ouviste a minha voz.");
    b->dados[JEREMIAS].capitulos[2].versos[3] = wxT("Pois me lançaste no profundo, no coração dos mares, e a corrente das águas me cercou; todas as tuas ondas e as tuas vagas passaram por cima de mim.");
    b->dados[JEREMIAS].capitulos[2].versos[4] = wxT("E eu disse: Lançado estou de diante dos teus olhos; como tornarei a olhar para o teu santo templo?");
    b->dados[JEREMIAS].capitulos[2].versos[5] = wxT("As águas me cercaram até a alma, o abismo me rodeou, e as algas se enrolaram na minha cabeça.");
    b->dados[JEREMIAS].capitulos[2].versos[6] = wxT("Eu desci até os fundamentos dos montes; a terra encerrou-me para sempre com os seus ferrolhos; mas tu, Senhor meu Deus, fizeste subir da cova a minha vida.");
    b->dados[JEREMIAS].capitulos[2].versos[7] = wxT("Quando dentro de mim desfalecia a minha alma, eu me lembrei do Senhor; e entrou a ti a minha oração, no teu santo templo.");
    b->dados[JEREMIAS].capitulos[2].versos[8] = wxT("Os que se apegam aos vãos ídolos afastam de si a misericórdia.");
    b->dados[JEREMIAS].capitulos[2].versos[9] = wxT("Mas eu te oferecerei sacrifício com a voz de ação de graças; o que votei pagarei. Ao Senhor pertence a salvação.");
    b->dados[JEREMIAS].capitulos[2].versos[10] = wxT("Falou, pois, o Senhor ao peixe, e o peixe vomitou a Jonas na terra.");

    b->dados[JEREMIAS].capitulos[3].versos[1] = wxT("Pela segunda vez veio a palavra do Senhor a Jonas, dizendo:");
    b->dados[JEREMIAS].capitulos[3].versos[2] = wxT("Levanta-te, e vai à grande cidade de Nínive, e lhe proclama a mensagem que eu te ordeno.");
    b->dados[JEREMIAS].capitulos[3].versos[3] = wxT("Levantou-se, pois, Jonas, e foi a Nínive, segundo a palavra do Senhor. Ora, Nínive era uma grande cidade, de três dias de jornada.");
    b->dados[JEREMIAS].capitulos[3].versos[4] = wxT("E começou Jonas a entrar pela cidade, fazendo a jornada dum dia, e clamava, dizendo: Ainda quarenta dias, e Nínive será subvertida.");
    b->dados[JEREMIAS].capitulos[3].versos[5] = wxT("E os homens de Nínive creram em Deus; e proclamaram um jejum, e vestiram-se de saco, desde o maior deles até o menor.");
    b->dados[JEREMIAS].capitulos[3].versos[6] = wxT("A notícia chegou também ao rei de Nínive; e ele se levantou do seu trono e, despindo-se do seu manto e cobrindo-se de saco, sentou-se sobre cinzas.");
    b->dados[JEREMIAS].capitulos[3].versos[7] = wxT("E fez uma proclamação, e a publicou em Nínive, por decreto do rei e dos seus nobres, dizendo: Não provem coisa alguma nem homens, nem animais, nem bois, nem ovelhas; não comam, nem bebam água;");
    b->dados[JEREMIAS].capitulos[3].versos[8] = wxT("mas sejam cobertos de saco, tanto os homens como os animais, e clamem fortemente a Deus; e convertam-se, cada um do seu mau caminho, e da violência que há nas suas mãos.");
    b->dados[JEREMIAS].capitulos[3].versos[9] = wxT("Quem sabe se voltará Deus, e se arrependerá, e se apartará do furor da sua ira, de sorte que não pereçamos?");
    b->dados[JEREMIAS].capitulos[3].versos[10] = wxT("Viu Deus o que fizeram, como se converteram do seu mau caminho, e Deus se arrependeu do mal que tinha dito lhes faria, e não o fez.");

    b->dados[JEREMIAS].capitulos[4].versos[1] = wxT("Mas isso desagradou extremamente a Jonas, e ele ficou irado.");
    b->dados[JEREMIAS].capitulos[4].versos[2] = wxT("E orou ao Senhor, e disse: Ah! Senhor! não foi isso o que eu disse, estando ainda na minha terra? Por isso é que me apressei a fugir para Társis, pois eu sabia que és Deus compassivo e misericordioso, longânimo e grande em benignidade, e que te arrependes do mal.");
    b->dados[JEREMIAS].capitulos[4].versos[3] = wxT("Agora, ó Senhor, tira-me a vida, pois melhor me é morrer do que viver.");
    b->dados[JEREMIAS].capitulos[4].versos[4] = wxT("Respondeu o senhor: É razoável essa tua ira?");
    b->dados[JEREMIAS].capitulos[4].versos[5] = wxT("Então Jonas saiu da cidade, e sentou-se ao oriente dela; e ali fez para si uma barraca, e se sentou debaixo dela, à sombra, até ver o que aconteceria à cidade.");
    b->dados[JEREMIAS].capitulos[4].versos[6] = wxT("E fez o Senhor Deus nascer uma aboboreira, e fê-la crescer por cima de Jonas, para que lhe fizesse sombra sobre a cabeça, a fim de o livrar do seu enfado; de modo que Jonas se alegrou em extremo por causa da aboboreira.");
    b->dados[JEREMIAS].capitulos[4].versos[7] = wxT("Mas Deus enviou um bicho, no dia seguinte ao subir da alva, o qual feriu a aboboreira, de sorte que esta se secou.");
    b->dados[JEREMIAS].capitulos[4].versos[8] = wxT("E aconteceu que, aparecendo o sol, Deus mandou um vento calmoso oriental; e o sol bateu na cabeça de Jonas, de maneira que ele desmaiou, e desejou com toda a sua alma morrer, dizendo: Melhor me é morrer do que viver.");
    b->dados[JEREMIAS].capitulos[4].versos[9] = wxT("Então perguntou Deus a Jonas: É razoável essa tua ira por causa da aboboreira? Respondeu ele: É justo que eu me enfade a ponto de desejar a morte.");
    b->dados[JEREMIAS].capitulos[4].versos[10] = wxT("Disse, pois, o Senhor: Tens compaixão da aboboreira, na qual não trabalhaste, nem a fizeste crescer; que numa noite nasceu, e numa noite pereceu.");
    b->dados[JEREMIAS].capitulos[4].versos[11] = wxT("E não hei de eu ter compaixão da grande cidade de Nínive em que há mais de cento e vinte mil pessoas que não sabem discernir entre a sua mão direita e a esquerda, e também muito gado?");

}
